`timescale 1 ns/1 ps
`define ARM_MEM_PROP 1.000
`define ARM_MEM_RETAIN 1.000
`define ARM_MEM_PERIOD 3.000
`define ARM_MEM_WIDTH 1.000
`define ARM_MEM_SETUP 1.000
`define ARM_MEM_HOLD 0.500
`define ARM_MEM_COLLISION 3.000
`define ARM_OFFSET_TIME 0

`include "cam_defines.vh"
  `define SRAM_SP_UHDE_HVT_MVT_ARM_REF_EMA_VALUE   `EMA_VALUE_SP 
  `define SRAM_SP_UHDE_HVT_MVT_ARM_REF_EMAW_VALUE  `EMAW_VALUE_SP
  `define SRAM_SP_UHDE_HVT_MVT_ARM_REF_EMAS_VALUE  `EMAS_VALUE_SP

module datapath_latch_sram_cam_disp_8KB (CLK,Q_update,D_update,SE,SI,D,DFTRAMBYP,mem_path,XQ,Q);
	input CLK,Q_update,D_update,SE,SI,D,DFTRAMBYP,mem_path,XQ;
	output Q;

	reg    D_int;
	reg    Q;

   //  Model PHI2 portion
   always @(CLK or SE or SI or D) begin
      if (CLK === 1'b0) begin
         if (SE===1'b1)
           D_int=SI;
         else if (SE===1'bx)
           D_int=1'bx;
         else
           D_int=D;
      end
   end

   // model output side of RAM latch
   always @(posedge Q_update or posedge D_update or mem_path or posedge XQ) begin
      if (XQ===1'b0) begin
         if (DFTRAMBYP===1'b1)
           Q=D_int;
         else
           Q=mem_path;
      end
      else
        Q=1'bx;
   end
endmodule // datapath_latch_sram_cam_disp_8KB

